// Endpoint para adjuntar el PDF del presupuesto a la tarea de Asana
// que originó la importación. El front genera el PDF con html2pdf, lo
// codifica a base64 y nos lo manda en JSON. Aquí lo convertimos a un
// item binario que el nodo httpRequest siguiente envía como
// multipart/form-data al endpoint /tasks/{gid}/attachments de Asana.
//
// Body esperado:
//   {
//     asana_gid:   '12345678901234',          // gid de la tarea destino
//     filename:    'PRES-0042.pdf',           // nombre del archivo
//     pdf_base64:  '<base64 sin data: prefix>' // contenido del PDF
//   }
const raw = $input.first().json || {};
const b = (raw.body && typeof raw.body === 'object') ? raw.body : raw;
const asana_gid = String(b.asana_gid || '').trim();
const filename  = String(b.filename  || 'presupuesto.pdf').trim();
let pdf_base64 = String(b.pdf_base64 || '').trim();
if (pdf_base64.startsWith('data:')) {
  // Quita el prefijo "data:application/pdf;base64," si el front no lo limpió.
  const i = pdf_base64.indexOf(',');
  if (i >= 0) pdf_base64 = pdf_base64.slice(i + 1);
}
const errores = [];
if (!asana_gid)                          errores.push('asana_gid obligatorio');
if (asana_gid && !/^\d{6,}$/.test(asana_gid)) errores.push('asana_gid debe ser numérico');
if (!pdf_base64)                         errores.push('pdf_base64 obligatorio');
if (pdf_base64.length > 12 * 1024 * 1024) errores.push('pdf_base64 supera ~9 MB de PDF (limite por upload)');
if (errores.length) {
  return [{ json: { __error: true, __errores: errores } }];
}

const buf = Buffer.from(pdf_base64, 'base64');
return [{
  json: { asana_gid, filename },
  binary: {
    file: {
      data: buf.toString('base64'),
      mimeType: 'application/pdf',
      fileName: filename
    }
  }
}];

// Normaliza la respuesta de Asana al shape contractual
//   { success, attachment, errores }
// donde attachment = { gid, name, permanent_url, ... } cuando todo va
// bien. Si Preparar binario emitió __error, lo propagamos sin tocar Asana.
const prep = $('Preparar binario').first().json || {};
if (prep.__error) {
  return [{ json: { success: false, attachment: null, errores: prep.__errores || ['validación falló'] } }];
}
const resp = ($input.first() || {}).json || {};
if (resp && resp.errors && Array.isArray(resp.errors)) {
  return [{ json: { success: false, attachment: null, errores: resp.errors.map(e => e.message || String(e)) } }];
}
const data = resp.data || resp;
if (!data || !data.gid) {
  return [{ json: { success: false, attachment: null, errores: ['Asana no devolvió un attachment válido'] } }];
}
return [{ json: {
  success: true,
  attachment: {
    gid: data.gid,
    name: data.name || null,
    permanent_url: data.permanent_url || data.view_url || null,
    download_url:  data.download_url || null
  },
  errores: []
} }];
